mapper.insert:
SELECT 'ANN' || LPAD( NVL(MAX(TO_NUMBER(REGEXP_REPLACE(ann_no, '[^0-9]', ''))), 0) + 1 , 4, '0') FROM center_ann_board_post
/* kr.or.ddit.domain.central.admin.mapper.AnnouncementMapper.insertAnnouncement */ /* 공고 등록 */
INSERT INTO center_ann_board_post ( ann_no , board_no , ttl , cn , wrtr_id , top_fix_yn , pblanc_bgng_dt , pblanc_end_dt , rcrt_bgng_dt , rcrt_end_dt , reg_dttm , inq_cnt , sbmsn_doc , atch_file_id , del_yn , opn_yn ) VALUES ( #{annNo} , ( SELECT board_no FROM ( SELECT cbi.board_no FROM center_board_instance cbi WHERE cbi.apt_cmplex_no = #{aptCmplexNo} AND NVL(cbi.use_yn, 'Y') = 'Y' AND (cbi.board_ty_cd = 'ANN' OR cbi.board_nm LIKE '%공고%') ORDER BY cbi.board_no ) WHERE ROWNUM = 1 ) , #{ttl} , #{cn} , #{wrtrId} , NVL(#{topFixYn}, 'N') , TO_DATE(#{pblancBgngDt}, 'YYYY-MM-DD') , TO_DATE(#{pblancEndDt}, 'YYYY-MM-DD') , TO_DATE(#{rcrtBgngDt}, 'YYYY-MM-DD') , TO_DATE(#{rcrtEndDt}, 'YYYY-MM-DD') , SYSDATE , 0 , #{sbmsnDoc} , #{atchFileId} , NVL(#{delYn}, 'N') , NVL(#{opnYn}, 'Y') )

mapper.update:
/* kr.or.ddit.domain.central.admin.mapper.AnnouncementMapper.updateAnnouncement */
/* 공고 수정 */

UPDATE center_ann_board_post
SET
ttl = #{ttl}
, cn = #{cn}
, sbmsn_doc = #{sbmsnDoc}
, pblanc_bgng_dt = TO_DATE(#{pblancBgngDt}, 'YYYY-MM-DD')
, pblanc_end_dt = TO_DATE(#{pblancEndDt}, 'YYYY-MM-DD')
, rcrt_bgng_dt = TO_DATE(#{rcrtBgngDt}, 'YYYY-MM-DD')
, rcrt_end_dt = TO_DATE(#{rcrtEndDt}, 'YYYY-MM-DD')
, mdf_dttm = SYSDATE
WHERE ann_no = #{annNo}
AND NVL(del_yn, 'N') = 'N'

/* kr.or.ddit.domain.central.admin.mapper.AnnouncementMapper.deleteAnnouncement */
/* 공고 삭제 처리 */

UPDATE center_ann_board_post
SET
del_yn = 'Y'
, mdf_dttm = SYSDATE
WHERE ann_no = #{annNo}
